import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";import"./chunks/assets.BeMJz2iD.js";var i=JSON.parse(`{"title":"ACM程序设计竞赛","description":"ACM程序设计竞赛（ACM-XCPC）简介及参赛指南，涵盖集训队招新、训练安排、比赛规则等内容","frontmatter":{"lang":"zh-CN","title":"ACM程序设计竞赛","description":"ACM程序设计竞赛（ACM-XCPC）简介及参赛指南，涵盖集训队招新、训练安排、比赛规则等内容"},"headers":[],"relativePath":"en/learn/extra/contest/ACM.md","filePath":"en/learn/extra/contest/ACM.md","lastUpdated":1784220723000}`),a={name:`en/learn/extra/contest/ACM.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/extra/contest/ACM.md for this page in Markdown format</div><h1 id="acm-竞赛介绍" tabindex="-1">ACM 竞赛介绍 <a class="header-anchor" href="#acm-竞赛介绍" aria-label="Permalink to “ACM 竞赛介绍”">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h2><p><strong>主办方：国际计算机协会（ACM）</strong></p><p>ACM国际大学生程序设计竞赛（ACM International Collegiate Programming Contest，简称 <strong>ACM-ICPC</strong>），是全球最具影响力的大学生算法竞赛之一。比赛以团队形式进行，每支队伍由三名成员组成，主要考察选手在算法设计、编程能力以及团队协作方面的综合水平。</p><p>华南理工大学 ACM 集训队负责组织和选拔校内优秀学生参与各类赛事，包括：</p><ul><li><strong>ICPC（国际大学生程序设计竞赛）</strong></li><li><strong>CCPC（中国大学生程序设计竞赛）</strong></li><li><strong>GDCPC（广东省大学生程序设计竞赛）</strong></li><li><strong>华工周边高校联合校赛（广工、广大、华师、暨大等）</strong></li><li><strong>蓝桥杯、企业赞助类竞赛等</strong></li></ul><hr><h2 id="acm-比赛规则概览" tabindex="-1">ACM 比赛规则概览 <a class="header-anchor" href="#acm-比赛规则概览" aria-label="Permalink to “ACM 比赛规则概览”">​</a></h2><h3 id="比赛形式" tabindex="-1">比赛形式 <a class="header-anchor" href="#比赛形式" aria-label="Permalink to “比赛形式”">​</a></h3><ul><li><strong>三人一队</strong></li><li><strong>仅队长电脑可提交代码</strong></li><li>其他两名队员只能阅读题目和讨论思路</li><li><strong>比赛时长：5 小时</strong></li><li><strong>题量：7~12 道题目不等</strong></li><li><strong>允许携带纸质资料</strong></li><li><strong>常用语言：C++、Java、Python（推荐 C++，速度更快）</strong></li><li><strong>题面全英文</strong></li></ul><p>一般来说，ACM 相关比赛题目一般由以下几个部分组成：</p><ul><li><strong>Time Limit</strong>：时间限制</li><li><strong>Memory Limit</strong>：内存限制</li><li><strong>Description</strong>：题目描述</li><li><strong>Input</strong>：输入描述</li><li><strong>Output</strong>：输出描述</li><li><strong>Sample Input/Output</strong>：输入输出样例</li></ul><p>提交的代码也有以下几种运行结果：</p><table tabindex="0"><thead><tr><th>结果缩写</th><th>全称</th><th>含义</th></tr></thead><tbody><tr><td>AC</td><td>Accept</td><td>运行通过</td></tr><tr><td>WA</td><td>Wrong Answer</td><td>答案错误</td></tr><tr><td>CE</td><td>Compile Error</td><td>编译错误</td></tr><tr><td>TLE</td><td>Time Limit Exceeded</td><td>时间超限</td></tr><tr><td>MLE</td><td>Memory Limit Exceeded</td><td>内存超限</td></tr><tr><td>PE</td><td>Presentation Error</td><td>格式错误</td></tr></tbody></table><blockquote><p>⚠️ 只有 <strong>AC</strong> 才是通过题目，其他运行结果都代表代码有问题。</p></blockquote><h3 id="得分机制" tabindex="-1">得分机制 <a class="header-anchor" href="#得分机制" aria-label="Permalink to “得分机制”">​</a></h3><ul><li><strong>首先看通过题目数量</strong>：越多排名越靠前</li><li><strong>其次看总用时</strong>：总用时 = ∑(每道题的通过时间 + 罚时) <ul><li>每次错误提交（除 CE 外）罚时 20 分钟</li><li>只有题目通过后才计算罚时</li></ul></li><li><strong>封榜机制</strong>：比赛结束前 1 小时榜单冻结，最终结果在赛后揭晓（可能出现“滚榜”现象）</li></ul><h3 id="奖励机制" tabindex="-1">奖励机制 <a class="header-anchor" href="#奖励机制" aria-label="Permalink to “奖励机制”">​</a></h3><ul><li>通过题目可获得气球</li><li>首位通过某题的队伍会获得特殊气球</li></ul><hr><h2 id="集训队选拔与训练规划" tabindex="-1">集训队选拔与训练规划 <a class="header-anchor" href="#集训队选拔与训练规划" aria-label="Permalink to “集训队选拔与训练规划”">​</a></h2><h3 id="_1-招新时间" tabindex="-1">1. 招新时间 <a class="header-anchor" href="#_1-招新时间" aria-label="Permalink to “1. 招新时间”">​</a></h3><ul><li><strong>每年仅一次招新机会</strong>，通常在学年伊始。</li><li>错过将需等待下一年，建议尽早准备！</li></ul><h3 id="_2-训练安排" tabindex="-1">2. 训练安排 <a class="header-anchor" href="#_2-训练安排" aria-label="Permalink to “2. 训练安排”">​</a></h3><ul><li><strong>常规训练</strong>：每周周末安排 5 小时集训（模拟正式比赛时长）</li><li><strong>寒暑假集训</strong>： <ul><li><strong>寒假</strong>：由高年级学长传授基础算法知识</li><li><strong>暑假</strong>：参加全国高校联合集训</li></ul></li></ul><h3 id="_3-赛事参与" tabindex="-1">3. 赛事参与 <a class="header-anchor" href="#_3-赛事参与" aria-label="Permalink to “3. 赛事参与”">​</a></h3><ul><li>主要目标赛事为 <strong>ICPC</strong> 和 <strong>CCPC</strong></li><li>上学期通过网络赛获得区域赛资格</li><li>表现优异者可晋级 <strong>EC-Final</strong> 或 <strong>CCPC Final</strong></li><li>推荐参与其他赛事如蓝桥杯、企业赞助赛，既有机会获得奖金，也可用于综测加分</li></ul><hr><h2 id="报名方式与时间节点" tabindex="-1">报名方式与时间节点 <a class="header-anchor" href="#报名方式与时间节点" aria-label="Permalink to “报名方式与时间节点”">​</a></h2><h3 id="报名渠道" tabindex="-1">报名渠道 <a class="header-anchor" href="#报名渠道" aria-label="Permalink to “报名渠道”">​</a></h3><ul><li><strong>校内选拔</strong>：通过学校组织的 ACM 校赛选拔进入集训队</li></ul><h3 id="比赛时间" tabindex="-1">比赛时间 <a class="header-anchor" href="#比赛时间" aria-label="Permalink to “比赛时间”">​</a></h3><table tabindex="0"><thead><tr><th>赛事</th><th>时间安排</th></tr></thead><tbody><tr><td>ICPC / CCPC</td><td>一般为每年秋季学期举办</td></tr><tr><td>GDCPC</td><td>省内赛通常安排在春季学期</td></tr><tr><td>蓝桥杯</td><td>初赛在春季，决赛在夏季</td></tr></tbody></table><hr><h2 id="集训队优势" tabindex="-1">集训队优势 <a class="header-anchor" href="#集训队优势" aria-label="Permalink to “集训队优势”">​</a></h2><ul><li><strong>学习资源丰富</strong>：资深学长一对一答疑，涵盖学习、生活等多个方面</li><li><strong>人脉拓展</strong>：结识志同道合的队友，未来合作项目或求职更具优势</li><li><strong>实践机会</strong>：寒暑假集训可计入社会实践经历</li><li><strong>综测加分</strong>：拿奖可加智育分</li><li><strong>保研加分</strong>：竞赛成绩优异者在保研复试中具备更强的机试能力，尤其对计算机相关专业深造有明显帮助。<em>（注：具体保研政策请以所在学院规定为准）</em></li><li><strong>就业优势</strong>：参与企业赞助类竞赛并获奖，有机会直接获得知名企业实习或录用资格。拥有扎实的算法基础和实战经验，在技术面试中更具优势。同时，已有工作的学长可提供内部推荐资源，大幅提升求职成功率。</li><li><strong>科研助力</strong>：实验室老师更青睐有竞赛背景的学生</li></ul><hr><h2 id="新生入门建议" tabindex="-1">新生入门建议 <a class="header-anchor" href="#新生入门建议" aria-label="Permalink to “新生入门建议”">​</a></h2><h3 id="编程语言选择" tabindex="-1">编程语言选择 <a class="header-anchor" href="#编程语言选择" aria-label="Permalink to “编程语言选择”">​</a></h3><ul><li><strong>推荐使用 C++</strong>：速度快，适合算法竞赛</li><li>Python / Java 因解释型语言特性，容易超时，仅适用于极少数大数运算题目</li></ul><h3 id="开发环境建议" tabindex="-1">开发环境建议 <a class="header-anchor" href="#开发环境建议" aria-label="Permalink to “开发环境建议”">​</a></h3><ul><li><strong>Windows 平台</strong>： <ul><li>新手推荐使用 <strong>Code::Blocks</strong> 或 <strong>Dev-C++</strong></li><li>有能力者可使用 <strong>VSCode + MinGW / WSL + GNU G++</strong></li></ul></li><li><strong>Linux 用户</strong>：自行配置即可</li><li><strong>Mac 用户</strong>：可尝试 VSCode + Clang 编译器</li></ul><h3 id="学习资源推荐" tabindex="-1">学习资源推荐 <a class="header-anchor" href="#学习资源推荐" aria-label="Permalink to “学习资源推荐”">​</a></h3><ul><li><strong>C++ 快速入门</strong>：<a href="https://www.runoob.com/cplusplus/cpp-tutorial.html" target="_blank" rel="noreferrer">菜鸟教程 - C++</a></li><li><strong>OI Wiki</strong>：<a href="https://oi-wiki.org/" target="_blank" rel="noreferrer">OI-Wiki</a></li><li><strong>刷题平台</strong>： <ul><li><a href="https://www.luogu.com.cn/" target="_blank" rel="noreferrer">洛谷</a></li><li><a href="https://leetcode.cn/problemset/all/" target="_blank" rel="noreferrer">LeetCode</a></li><li><a href="https://codeforces.com/" target="_blank" rel="noreferrer">Codeforces</a></li></ul></li><li><strong>算法模板</strong>： <ul><li><a href="https://www.cnblogs.com/WIDA/p/17633758.html" target="_blank" rel="noreferrer">jiangly 算法模板收集 - hh2048 - 博客园</a></li></ul></li></ul><h3 id="初学者学习路径" tabindex="-1">初学者学习路径 <a class="header-anchor" href="#初学者学习路径" aria-label="Permalink to “初学者学习路径”">​</a></h3><ol><li>学习基础语法（推荐《深入浅出程序设计竞赛》）</li><li>掌握基本算法： <ul><li>二分查找</li><li>贪心算法</li><li>动态规划（DP）</li><li>搜索（DFS/BFS）</li></ul></li><li>提升英语阅读能力（题面均为英文）</li></ol><hr><h2 id="备战策略-针对新生" tabindex="-1">备战策略（针对新生） <a class="header-anchor" href="#备战策略-针对新生" aria-label="Permalink to “备战策略（针对新生）”">​</a></h2><h3 id="快速入门路线" tabindex="-1">快速入门路线 <a class="header-anchor" href="#快速入门路线" aria-label="Permalink to “快速入门路线”">​</a></h3><ol><li><strong>掌握 C++ 基础语法</strong>： <ul><li>数据类型、循环结构、函数定义、数组与字符串操作</li></ul></li><li><strong>熟悉 STL 库</strong>： <ul><li><code>vector</code>, <code>map</code>, <code>set</code>, <code>priority_queue</code> 等常用容器</li></ul></li><li><strong>刷题积累经验</strong>： <ul><li>从简单题开始，逐步挑战中等难度题目</li></ul></li><li><strong>模拟实战演练</strong>： <ul><li>每周参与一次 5 小时模拟赛，适应比赛节奏</li></ul></li></ol><h3 id="学习书籍推荐" tabindex="-1">学习书籍推荐 <a class="header-anchor" href="#学习书籍推荐" aria-label="Permalink to “学习书籍推荐”">​</a></h3><ul><li>《深入浅出程序设计竞赛》（洛谷出版）</li><li>《算法竞赛入门经典》（刘汝佳著） <img src="/assets/%E6%B7%B1%E5%85%A5%E6%B5%85%E5%87%BA%E7%A8%8B%E5%BA%8F%E8%AE%BE%E8%AE%A1%E7%AB%9E%E8%B5%9B.CMB8JIdi.jpg" alt="深入浅出程序设计竞赛"></li></ul><p><img src="/assets/%E7%AE%97%E6%B3%95%E7%AB%9E%E8%B5%9B%E5%85%A5%E9%97%A8%E7%BB%8F%E5%85%B8.CgPwATiq.jpg" alt="算法竞赛入门经典"></p><h3 id="提升方向" tabindex="-1">提升方向 <a class="header-anchor" href="#提升方向" aria-label="Permalink to “提升方向”">​</a></h3><ul><li><strong>阅读英文题面能力</strong>：多做原题训练</li><li><strong>调试技巧</strong>：学会使用调试工具排查错误</li><li><strong>时间管理</strong>：合理分配解题时间，避免卡题</li></ul><hr><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to “结语”">​</a></h2><p>加入 ACM 集训队不仅是锻炼编程能力和逻辑思维的绝佳机会，更是通往更高学术平台和优质就业机会的重要跳板。只要你愿意投入时间和精力，勇于挑战自我，就有机会脱颖而出，成为华工 ACM 战队的一员！</p><p><strong>2025华工ACM集训队招新群</strong>：557553053 (QQ 群)</p>`,60)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};